        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/AgentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Strings.sol";

/**
 * @title AgentRegistry
 * @notice On-chain registry for AI agents on Arc L1
 * @dev Agents register their identity, skills, and rates
 */
contract AgentRegistry is Ownable {
    using Strings for uint256;

    struct Agent {
        address wallet;
        string name;
        string description;
        string[] skills;
        uint256 ratePerTask;      // USDC (6 decimals)
        uint256 ratePerCall;      // USDC (6 decimals)
        uint256 completedTasks;
        uint256 totalEarnings;
        uint256 ratingSum;        // Sum of ratings (for avg calc)
        uint256 ratingCount;
        uint256 registeredAt;
        bool isActive;
        string metadataURI;       // IPFS URI for extended profile
    }

    // State
    mapping(address => Agent) public agents;
    address[] public agentList;
    mapping(string => address[]) public skillIndex;

    // Events
    event AgentRegistered(address indexed wallet, string name, string[] skills);
    event AgentUpdated(address indexed wallet, string[] skills, uint256 ratePerTask, uint256 ratePerCall);
    event AgentDeactivated(address indexed wallet);
    event AgentReactivated(address indexed wallet);
    event AgentRatingUpdated(address indexed wallet, uint256 newRating, uint256 ratingCount);

    // Modifiers
    modifier onlyRegisteredAgent() {
        require(agents[msg.sender].wallet != address(0), "Agent not registered");
        _;
    }

    modifier onlyActiveAgent() {
        require(agents[msg.sender].isActive, "Agent not active");
        _;
    }

    constructor() Ownable(msg.sender) {}

    /**
     * @notice Register a new agent
     * @param name Agent display name
     * @param description What the agent does
     * @param skills Array of skill tags
     * @param ratePerTask Base rate per task in USDC
     * @param ratePerCall Rate per API call in USDC
     * @param metadataURI IPFS URI for extended profile
     */
    function registerAgent(
        string memory name,
        string memory description,
        string[] memory skills,
        uint256 ratePerTask,
        uint256 ratePerCall,
        string memory metadataURI
    ) external {
        require(agents[msg.sender].wallet == address(0), "Already registered");
        require(bytes(name).length > 0, "Name required");
        require(skills.length > 0, "At least one skill required");

        Agent storage agent = agents[msg.sender];
        agent.wallet = msg.sender;
        agent.name = name;
        agent.description = description;
        agent.skills = skills;
        agent.ratePerTask = ratePerTask;
        agent.ratePerCall = ratePerCall;
        agent.registeredAt = block.timestamp;
        agent.isActive = true;
        agent.metadataURI = metadataURI;

        agentList.push(msg.sender);

        // Index skills
        for (uint256 i = 0; i < skills.length; i++) {
            skillIndex[skills[i]].push(msg.sender);
        }

        emit AgentRegistered(msg.sender, name, skills);
    }

    /**
     * @notice Update agent profile
     */
    function updateAgent(
        string[] memory skills,
        uint256 ratePerTask,
        uint256 ratePerCall,
        string memory metadataURI
    ) external onlyRegisteredAgent {
        Agent storage agent = agents[msg.sender];
        agent.skills = skills;
        agent.ratePerTask = ratePerTask;
        agent.ratePerCall = ratePerCall;
        agent.metadataURI = metadataURI;

        emit AgentUpdated(msg.sender, skills, ratePerTask, ratePerCall);
    }

    /**
     * @notice Deactivate agent (pause accepting tasks)
     */
    function deactivateAgent() external onlyRegisteredAgent onlyActiveAgent {
        agents[msg.sender].isActive = false;
        emit AgentDeactivated(msg.sender);
    }

    /**
     * @notice Reactivate agent
     */
    function reactivateAgent() external onlyRegisteredAgent {
        require(!agents[msg.sender].isActive, "Already active");
        agents[msg.sender].isActive = true;
        emit AgentReactivated(msg.sender);
    }

    /**
     * @notice Update agent rating (called by Reputation contract)
     */
    function updateRating(address agent, uint256 rating) external {
        // Only allow Reputation contract to call
        // For now, only owner can set (will be updated when Reputation is deployed)
        require(msg.sender == owner(), "Only reputation contract");

        Agent storage a = agents[agent];
        a.ratingSum += rating;
        a.ratingCount += 1;

        emit AgentRatingUpdated(agent, a.ratingSum / a.ratingCount, a.ratingCount);
    }

    /**
     * @notice Record task completion
     */
    function recordTaskCompletion(address agent, uint256 earnings) external {
        require(msg.sender == owner(), "Only task escrow contract");
        agents[agent].completedTasks += 1;
        agents[agent].totalEarnings += earnings;
    }

    // View functions
    function getAgent(address wallet) external view returns (
        string memory name,
        string memory description,
        string[] memory skills,
        uint256 ratePerTask,
        uint256 ratePerCall,
        uint256 completedTasks,
        uint256 totalEarnings,
        uint256 averageRating,
        uint256 ratingCount,
        bool isActive,
        string memory metadataURI
    ) {
        Agent storage a = agents[wallet];
        return (
            a.name,
            a.description,
            a.skills,
            a.ratePerTask,
            a.ratePerCall,
            a.completedTasks,
            a.totalEarnings,
            a.ratingCount > 0 ? a.ratingSum / a.ratingCount : 0,
            a.ratingCount,
            a.isActive,
            a.metadataURI
        );
    }

    function getAgentCount() external view returns (uint256) {
        return agentList.length;
    }

    function getAgentByIndex(uint256 index) external view returns (address) {
        return agentList[index];
    }

    function getAgentsBySkill(string memory skill) external view returns (address[] memory) {
        return skillIndex[skill];
    }

    function getAverageRating(address wallet) external view returns (uint256) {
        Agent storage a = agents[wallet];
        if (a.ratingCount == 0) return 0;
        return a.ratingSum / a.ratingCount;
    }

    function isRegistered(address wallet) external view returns (bool) {
        return agents[wallet].wallet != address(0);
    }

    function isActive(address wallet) external view returns (bool) {
        return agents[wallet].isActive;
    }

    // Update name and description
    function updateProfile(string memory name, string memory description) external onlyRegisteredAgent {
        agents[msg.sender].name = name;
        agents[msg.sender].description = description;
    }
}

contracts/MicroPayment.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title MicroPayment
 * @notice Payment streams for per-call or per-second billing
 */
contract MicroPayment is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    enum StreamType { PerCall, PerSecond }

    struct Stream {
        uint256 id;
        address sender;
        address receiver;
        uint256 ratePerUnit;      // USDC per unit
        uint256 cap;              // Max total payment
        uint256 totalDeposited;
        uint256 totalWithdrawn;
        uint256 unitsConsumed;
        uint256 createdAt;
        uint256 lastWithdrawAt;
        bool isActive;
        StreamType streamType;
    }

    IERC20 public usdc;
    uint256 public nextStreamId = 1;
    uint256 public platformFeePercent = 250; // 2.5%

    mapping(uint256 => Stream) public streams;
    mapping(address => uint256[]) public senderStreams;
    mapping(address => uint256[]) public receiverStreams;

    // Events
    event StreamCreated(uint256 indexed streamId, address indexed sender, address indexed receiver, uint256 ratePerUnit, uint256 cap, StreamType streamType);
    event StreamUnitRecorded(uint256 indexed streamId, uint256 unitsConsumed);
    event StreamWithdrawal(uint256 indexed streamId, address indexed receiver, uint256 amount);
    event StreamStopped(uint256 indexed streamId, uint256 refundAmount);
    event StreamDepositAdded(uint256 indexed streamId, uint256 amount);

    constructor(address _usdc) Ownable(msg.sender) {
        usdc = IERC20(_usdc);
    }

    /**
     * @notice Create a new payment stream
     * @param receiver Who receives payments
     * @param ratePerUnit USDC per call/second
     * @param cap Maximum total payment
     * @param streamType PerCall or PerSecond
     */
    function createStream(
        address receiver,
        uint256 ratePerUnit,
        uint256 cap,
        StreamType streamType
    ) external nonReentrant returns (uint256) {
        require(receiver != address(0), "Invalid receiver");
        require(ratePerUnit > 0, "Rate must be > 0");
        require(cap > 0, "Cap must be > 0");

        uint256 streamId = nextStreamId++;

        // Deposit initial funds
        usdc.safeTransferFrom(msg.sender, address(this), cap);

        Stream storage stream = streams[streamId];
        stream.id = streamId;
        stream.sender = msg.sender;
        stream.receiver = receiver;
        stream.ratePerUnit = ratePerUnit;
        stream.cap = cap;
        stream.totalDeposited = cap;
        stream.createdAt = block.timestamp;
        stream.isActive = true;
        stream.streamType = streamType;

        senderStreams[msg.sender].push(streamId);
        receiverStreams[receiver].push(streamId);

        emit StreamCreated(streamId, msg.sender, receiver, ratePerUnit, cap, streamType);
        return streamId;
    }

    /**
     * @notice Record usage (called by receiver for each call/second)
     */
    function recordUnit(uint256 streamId) external {
        Stream storage stream = streams[streamId];
        require(stream.isActive, "Stream not active");
        require(msg.sender == stream.receiver, "Not receiver");

        uint256 currentBalance = getStreamBalance(streamId);
        require(currentBalance >= stream.ratePerUnit, "Insufficient balance");

        stream.unitsConsumed += 1;

        emit StreamUnitRecorded(streamId, stream.unitsConsumed);
    }

    /**
     * @notice Batch record multiple units
     */
    function recordUnits(uint256 streamId, uint256 units) external {
        Stream storage stream = streams[streamId];
        require(stream.isActive, "Stream not active");
        require(msg.sender == stream.receiver, "Not receiver");

        uint256 currentBalance = getStreamBalance(streamId);
        uint256 totalCost = stream.ratePerUnit * units;
        require(currentBalance >= totalCost, "Insufficient balance");

        stream.unitsConsumed += units;

        emit StreamUnitRecorded(streamId, stream.unitsConsumed);
    }

    /**
     * @notice Receiver withdraws accumulated payments
     */
    function withdrawFromStream(uint256 streamId) external nonReentrant {
        Stream storage stream = streams[streamId];
        require(msg.sender == stream.receiver, "Not receiver");
        require(stream.isActive || stream.totalWithdrawn < getAccumulated(streamId), "Nothing to withdraw");

        uint256 accumulated = getAccumulated(streamId);
        uint256 available = accumulated - stream.totalWithdrawn;
        require(available > 0, "Nothing to withdraw");

        stream.totalWithdrawn += available;
        stream.lastWithdrawAt = block.timestamp;

        // Calculate fee
        uint256 fee = (available * platformFeePercent) / 10000;
        uint256 payout = available - fee;

        usdc.safeTransfer(stream.receiver, payout);
        if (fee > 0) {
            usdc.safeTransfer(owner(), fee);
        }

        emit StreamWithdrawal(streamId, stream.receiver, payout);
    }

    /**
     * @notice Sender stops stream and gets refund
     */
    function stopStream(uint256 streamId) external nonReentrant {
        Stream storage stream = streams[streamId];
        require(msg.sender == stream.sender, "Not sender");
        require(stream.isActive, "Not active");

        stream.isActive = false;

        // Pay out what's accumulated
        uint256 accumulated = getAccumulated(streamId);
        uint256 unpaid = accumulated - stream.totalWithdrawn;

        if (unpaid > 0) {
            uint256 fee = (unpaid * platformFeePercent) / 10000;
            uint256 payout = unpaid - fee;
            usdc.safeTransfer(stream.receiver, payout);
            stream.totalWithdrawn = accumulated;
        }

        // Refund remaining
        uint256 refund = stream.totalDeposited - stream.totalWithdrawn;
        if (refund > 0) {
            usdc.safeTransfer(stream.sender, refund);
        }

        emit StreamStopped(streamId, refund);
    }

    /**
     * @notice Add more funds to stream
     */
    function depositToStream(uint256 streamId, uint256 amount) external nonReentrant {
        Stream storage stream = streams[streamId];
        require(msg.sender == stream.sender, "Not sender");
        require(stream.isActive, "Not active");
        require(amount > 0, "Amount must be > 0");

        usdc.safeTransferFrom(msg.sender, address(this), amount);
        stream.totalDeposited += amount;
        stream.cap += amount;

        emit StreamDepositAdded(streamId, amount);
    }

    // View functions
    function getAccumulated(uint256 streamId) public view returns (uint256) {
        Stream storage stream = streams[streamId];
        return stream.unitsConsumed * stream.ratePerUnit;
    }

    function getStreamBalance(uint256 streamId) public view returns (uint256) {
        Stream storage stream = streams[streamId];
        uint256 accumulated = getAccumulated(streamId);
        return stream.cap - accumulated;
    }

    function getStream(uint256 streamId) external view returns (
        address sender,
        address receiver,
        uint256 ratePerUnit,
        uint256 cap,
        uint256 totalDeposited,
        uint256 totalWithdrawn,
        uint256 unitsConsumed,
        bool isActive,
        StreamType streamType
    ) {
        Stream storage s = streams[streamId];
        return (s.sender, s.receiver, s.ratePerUnit, s.cap, s.totalDeposited, s.totalWithdrawn, s.unitsConsumed, s.isActive, s.streamType);
    }

    function getSenderStreams(address sender) external view returns (uint256[] memory) {
        return senderStreams[sender];
    }

    function getReceiverStreams(address receiver) external view returns (uint256[] memory) {
        return receiverStreams[receiver];
    }

    function getStreamCount() external view returns (uint256) {
        return nextStreamId - 1;
    }

    // Admin
    function setPlatformFee(uint256 _feePercent) external onlyOwner {
        require(_feePercent <= 1000, "Max 10%");
        platformFeePercent = _feePercent;
    }
}

contracts/Reputation.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";

interface ITaskEscrow {
    function getTask(uint256 taskId) external view returns (
        address requester,
        address provider,
        uint256 budget,
        string memory description,
        uint8 status,
        uint256 createdAt,
        uint256 deadline,
        bytes32 deliverableHash,
        string memory deliverableURI
    );
}

interface IAgentRegistry {
    function updateRating(address agent, uint256 rating) external;
}

/**
 * @title Reputation
 * @notice On-chain reputation system with reviews and trust scores
 */
contract Reputation is Ownable {

    struct Review {
        uint256 id;
        address reviewer;
        address reviewee;
        uint256 taskId;
        uint8 rating;             // 1-5
        string comment;
        uint256 createdAt;
    }

    struct ReputationScore {
        uint256 averageRating;    // x100 for precision (e.g., 450 = 4.50)
        uint256 totalReviews;
        uint256 completedTasks;
        uint256 disputedTasks;
        uint256 totalEarnings;
        uint256 avgResponseTime;
        uint256 completionRate;   // x100 (e.g., 9500 = 95%)
    }

    address public taskEscrow;
    IAgentRegistry public agentRegistry;

    uint256 public nextReviewId = 1;

    // taskId => has been reviewed by this address
    mapping(uint256 => mapping(address => bool)) public hasReviewed;

    // reviewId => Review
    mapping(uint256 => Review) public reviews;

    // agent => reviewIds
    mapping(address => uint256[]) public agentReviews;

    // agent => reputation data
    mapping(address => ReputationScore) public reputation;

    // Events
    event ReviewSubmitted(uint256 indexed reviewId, address indexed reviewer, address reviewee, uint256 taskId, uint8 rating);

    constructor(address _taskEscrow, address _agentRegistry) Ownable(msg.sender) {
        taskEscrow = _taskEscrow;
        agentRegistry = IAgentRegistry(_agentRegistry);
    }

    /**
     * @notice Submit a review after task completion
     * @param taskId The completed task
     * @param rating 1-5 stars
     * @param comment Review comment
     */
    function submitReview(
        uint256 taskId,
        uint8 rating,
        string memory comment
    ) external {
        require(rating >= 1 && rating <= 5, "Rating must be 1-5");
        require(!hasReviewed[taskId][msg.sender], "Already reviewed");

        // Get task details
        (
            address requester,
            address provider,
            ,
            ,
            uint8 status,
            ,
            ,
            ,

        ) = ITaskEscrow(taskEscrow).getTask(taskId);

        // Only parties involved can review (status 5 = Paid)
        require(status == 5, "Task not paid");
        require(msg.sender == requester || msg.sender == provider, "Not involved");

        // Determine reviewee
        address reviewee = msg.sender == requester ? provider : requester;

        // Prevent self-review
        require(msg.sender != reviewee, "Cannot self-review");

        hasReviewed[taskId][msg.sender] = true;

        uint256 reviewId = nextReviewId++;
        Review storage review = reviews[reviewId];
        review.id = reviewId;
        review.reviewer = msg.sender;
        review.reviewee = reviewee;
        review.taskId = taskId;
        review.rating = rating;
        review.comment = comment;
        review.createdAt = block.timestamp;

        agentReviews[reviewee].push(reviewId);

        // Update reputation score
        _updateReputation(reviewee, rating);

        // Update AgentRegistry rating
        agentRegistry.updateRating(reviewee, rating);

        emit ReviewSubmitted(reviewId, msg.sender, reviewee, taskId, rating);
    }

    /**
     * @notice Get reputation score for an agent
     */
    function getReputation(address agent) external view returns (
        uint256 averageRating,
        uint256 totalReviews,
        uint256 completedTasks,
        uint256 disputedTasks,
        uint256 totalEarnings,
        uint256 avgResponseTime,
        uint256 completionRate
    ) {
        ReputationScore storage rep = reputation[agent];
        return (
            rep.averageRating,
            rep.totalReviews,
            rep.completedTasks,
            rep.disputedTasks,
            rep.totalEarnings,
            rep.avgResponseTime,
            rep.completionRate
        );
    }

    /**
     * @notice Get reviews for an agent with pagination
     */
    function getReviews(address agent, uint256 offset, uint256 limit) external view returns (
        uint256[] memory reviewIds,
        address[] memory reviewers,
        uint8[] memory ratings,
        string[] memory comments,
        uint256[] memory taskIds,
        uint256[] memory createdAts
    ) {
        uint256[] storage agentReviewIds = agentReviews[agent];
        uint256 end = offset + limit;
        if (end > agentReviewIds.length) {
            end = agentReviewIds.length;
        }
        uint256 count = end - offset;

        reviewIds = new uint256[](count);
        reviewers = new address[](count);
        ratings = new uint8[](count);
        comments = new string[](count);
        taskIds = new uint256[](count);
        createdAts = new uint256[](count);

        for (uint256 i = 0; i < count; i++) {
            uint256 rid = agentReviewIds[offset + i];
            Review storage r = reviews[rid];
            reviewIds[i] = rid;
            reviewers[i] = r.reviewer;
            ratings[i] = r.rating;
            comments[i] = r.comment;
            taskIds[i] = r.taskId;
            createdAts[i] = r.createdAt;
        }
    }

    /**
     * @notice Get composite trust score (0-100)
     * @dev Weighted: 60% rating + 30% completion rate + 10% task volume
     */
    function getTrustScore(address agent) external view returns (uint256) {
        ReputationScore storage rep = reputation[agent];

        if (rep.totalReviews == 0) return 0;

        // Rating component (0-60): avg rating / 5 * 60
        uint256 ratingScore = (rep.averageRating * 60) / 500;

        // Completion rate component (0-30)
        uint256 completionScore = (rep.completionRate * 30) / 10000;

        // Volume component (0-10): log scale, max at 100 tasks
        uint256 volumeScore = rep.completedTasks > 100 ? 10 : (rep.completedTasks * 10) / 100;

        return ratingScore + completionScore + volumeScore;
    }

    /**
     * @notice Check if a task has been reviewed by an address
     */
    function hasReviewForTask(uint256 taskId, address reviewer) external view returns (bool) {
        return hasReviewed[taskId][reviewer];
    }

    /**
     * @notice Get review count for an agent
     */
    function getReviewCount(address agent) external view returns (uint256) {
        return agentReviews[agent].length;
    }

    // Internal
    function _updateReputation(address agent, uint256 rating) internal {
        ReputationScore storage rep = reputation[agent];

        // Update average rating (weighted)
        uint256 totalRatingPoints = rep.averageRating * rep.totalReviews + rating;
        rep.totalReviews += 1;
        rep.averageRating = totalRatingPoints / rep.totalReviews;
    }

    // Admin
    function setTaskEscrow(address _taskEscrow) external onlyOwner {
        taskEscrow = _taskEscrow;
    }

    function setAgentRegistry(address _agentRegistry) external onlyOwner {
        agentRegistry = IAgentRegistry(_agentRegistry);
    }

    /**
     * @notice Update reputation stats from task events (admin only)
     */
    function updateStats(
        address agent,
        uint256 completedTasks,
        uint256 disputedTasks,
        uint256 totalEarnings,
        uint256 avgResponseTime,
        uint256 completionRate
    ) external onlyOwner {
        ReputationScore storage rep = reputation[agent];
        rep.completedTasks = completedTasks;
        rep.disputedTasks = disputedTasks;
        rep.totalEarnings = totalEarnings;
        rep.avgResponseTime = avgResponseTime;
        rep.completionRate = completionRate;
    }
}

contracts/TaskEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IAgentRegistry {
    function isRegistered(address wallet) external view returns (bool);
    function isActive(address wallet) external view returns (bool);
    function recordTaskCompletion(address agent, uint256 earnings) external;
}

/**
 * @title TaskEscrow
 * @notice Escrow-based task marketplace for AI agents
 */
contract TaskEscrow is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    enum TaskStatus {
        Open,
        Accepted,
        InProgress,
        Submitted,
        Approved,
        Paid,
        Disputed,
        Resolved,
        Cancelled,
        Expired
    }

    struct Task {
        uint256 id;
        address requester;
        address provider;
        uint256 budget;           // USDC amount escrowed
        string description;
        string[] requiredSkills;
        TaskStatus status;
        uint256 createdAt;
        uint256 deadline;
        uint256 submittedAt;
        bytes32 deliverableHash;  // IPFS CID hash
        string deliverableURI;
        uint256 disputeDeadline;
    }

    IERC20 public usdc;
    IAgentRegistry public agentRegistry;

    uint256 public platformFeePercent = 250; // 2.5% (basis points)
    uint256 public disputeWindow = 3 days;
    uint256 public nextTaskId = 1;

    mapping(uint256 => Task) public tasks;
    mapping(address => uint256[]) public requesterTasks;
    mapping(address => uint256[]) public providerTasks;

    // Events
    event TaskCreated(uint256 indexed taskId, address indexed requester, uint256 budget, string description);
    event TaskAccepted(uint256 indexed taskId, address indexed provider);
    event TaskSubmitted(uint256 indexed taskId, bytes32 deliverableHash, string deliverableURI);
    event TaskApproved(uint256 indexed taskId, uint256 paymentAmount);
    event TaskDisputed(uint256 indexed taskId, address indexed disputer, string reason);
    event TaskResolved(uint256 indexed taskId, uint256 requesterShare, uint256 providerShare);
    event TaskCancelled(uint256 indexed taskId);
    event TaskExpired(uint256 indexed taskId);

    constructor(address _usdc, address _agentRegistry) Ownable(msg.sender) {
        usdc = IERC20(_usdc);
        agentRegistry = IAgentRegistry(_agentRegistry);
    }

    /**
     * @notice Create a task with specific provider
     */
    function createTask(
        address provider,
        uint256 budget,
        string memory description,
        string[] memory requiredSkills,
        uint256 deadline
    ) external nonReentrant returns (uint256) {
        require(budget > 0, "Budget must be > 0");
        require(deadline > block.timestamp, "Deadline must be in future");
        require(bytes(description).length > 0, "Description required");

        if (provider != address(0)) {
            require(agentRegistry.isRegistered(provider), "Provider not registered");
            require(agentRegistry.isActive(provider), "Provider not active");
        }

        uint256 taskId = nextTaskId++;

        // Escrow USDC
        usdc.safeTransferFrom(msg.sender, address(this), budget);

        Task storage task = tasks[taskId];
        task.id = taskId;
        task.requester = msg.sender;
        task.provider = provider;
        task.budget = budget;
        task.description = description;
        task.requiredSkills = requiredSkills;
        task.status = provider != address(0) ? TaskStatus.Accepted : TaskStatus.Open;
        task.createdAt = block.timestamp;
        task.deadline = deadline;

        requesterTasks[msg.sender].push(taskId);
        if (provider != address(0)) {
            providerTasks[provider].push(taskId);
        }

        emit TaskCreated(taskId, msg.sender, budget, description);
        if (provider != address(0)) {
            emit TaskAccepted(taskId, provider);
        }

        return taskId;
    }

    /**
     * @notice Provider accepts an open task
     */
    function acceptTask(uint256 taskId) external nonReentrant {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Open, "Task not open");
        require(agentRegistry.isRegistered(msg.sender), "Not registered");
        require(agentRegistry.isActive(msg.sender), "Not active");
        require(task.deadline > block.timestamp, "Task expired");

        task.provider = msg.sender;
        task.status = TaskStatus.Accepted;
        providerTasks[msg.sender].push(taskId);

        emit TaskAccepted(taskId, msg.sender);
    }

    /**
     * @notice Provider marks task as in progress
     */
    function startTask(uint256 taskId) external {
        Task storage task = tasks[taskId];
        require(task.provider == msg.sender, "Not provider");
        require(task.status == TaskStatus.Accepted, "Not accepted");

        task.status = TaskStatus.InProgress;
    }

    /**
     * @notice Provider submits deliverable
     */
    function submitDeliverable(
        uint256 taskId,
        bytes32 deliverableHash,
        string memory deliverableURI
    ) external {
        Task storage task = tasks[taskId];
        require(task.provider == msg.sender, "Not provider");
        require(
            task.status == TaskStatus.Accepted || task.status == TaskStatus.InProgress,
            "Invalid status"
        );
        require(task.deadline > block.timestamp, "Task expired");

        task.deliverableHash = deliverableHash;
        task.deliverableURI = deliverableURI;
        task.submittedAt = block.timestamp;
        task.status = TaskStatus.Submitted;
        task.disputeDeadline = block.timestamp + disputeWindow;

        emit TaskSubmitted(taskId, deliverableHash, deliverableURI);
    }

    /**
     * @notice Requester approves and pays provider
     */
    function approveTask(uint256 taskId) external nonReentrant {
        Task storage task = tasks[taskId];
        require(task.requester == msg.sender, "Not requester");
        require(task.status == TaskStatus.Submitted, "Not submitted");

        task.status = TaskStatus.Approved;

        // Calculate payment
        uint256 fee = (task.budget * platformFeePercent) / 10000;
        uint256 providerPayment = task.budget - fee;

        // Transfer payment
        task.status = TaskStatus.Paid;
        usdc.safeTransfer(task.provider, providerPayment);

        if (fee > 0) {
            usdc.safeTransfer(owner(), fee);
        }

        // Record completion
        agentRegistry.recordTaskCompletion(task.provider, providerPayment);

        emit TaskApproved(taskId, providerPayment);
    }

    /**
     * @notice Either party can dispute
     */
    function disputeTask(uint256 taskId, string memory reason) external {
        Task storage task = tasks[taskId];
        require(
            task.requester == msg.sender || task.provider == msg.sender,
            "Not party"
        );
        require(task.status == TaskStatus.Submitted, "Not submitted");
        require(block.timestamp <= task.disputeDeadline, "Dispute window closed");

        task.status = TaskStatus.Disputed;

        emit TaskDisputed(taskId, msg.sender, reason);
    }

    /**
     * @notice Owner resolves dispute (simplified - full DAO voting later)
     */
    function resolveDispute(
        uint256 taskId,
        uint256 requesterPercent
    ) external onlyOwner {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Disputed, "Not disputed");
        require(requesterPercent <= 100, "Invalid percent");

        uint256 requesterShare = (task.budget * requesterPercent) / 100;
        uint256 providerShare = task.budget - requesterShare;

        if (requesterShare > 0) {
            usdc.safeTransfer(task.requester, requesterShare);
        }
        if (providerShare > 0) {
            usdc.safeTransfer(task.provider, providerShare);
        }

        task.status = TaskStatus.Resolved;

        emit TaskResolved(taskId, requesterShare, providerShare);
    }

    /**
     * @notice Cancel open task (refund requester)
     */
    function cancelTask(uint256 taskId) external nonReentrant {
        Task storage task = tasks[taskId];
        require(task.requester == msg.sender, "Not requester");
        require(task.status == TaskStatus.Open, "Not open");

        task.status = TaskStatus.Cancelled;
        usdc.safeTransfer(msg.sender, task.budget);

        emit TaskCancelled(taskId);
    }

    /**
     * @notice Expire task (auto-refund after deadline)
     */
    function expireTask(uint256 taskId) external nonReentrant {
        Task storage task = tasks[taskId];
        require(task.status == TaskStatus.Open || task.status == TaskStatus.Accepted, "Cannot expire");
        require(block.timestamp > task.deadline, "Not expired");

        task.status = TaskStatus.Expired;
        usdc.safeTransfer(task.requester, task.budget);

        emit TaskExpired(taskId);
    }

    // View functions
    function getTask(uint256 taskId) external view returns (
        address requester,
        address provider,
        uint256 budget,
        string memory description,
        TaskStatus status,
        uint256 createdAt,
        uint256 deadline,
        bytes32 deliverableHash,
        string memory deliverableURI
    ) {
        Task storage t = tasks[taskId];
        return (t.requester, t.provider, t.budget, t.description, t.status, t.createdAt, t.deadline, t.deliverableHash, t.deliverableURI);
    }

    function getRequesterTasks(address requester) external view returns (uint256[] memory) {
        return requesterTasks[requester];
    }

    function getProviderTasks(address provider) external view returns (uint256[] memory) {
        return providerTasks[provider];
    }

    function getTaskCount() external view returns (uint256) {
        return nextTaskId - 1;
    }

    // Admin
    function setPlatformFee(uint256 _feePercent) external onlyOwner {
        require(_feePercent <= 1000, "Max 10%");
        platformFeePercent = _feePercent;
    }

    function setDisputeWindow(uint256 _window) external onlyOwner {
        disputeWindow = _window;
    }
}

